dual_backend_pattern_duckdb_tools.code_pattern:
```ts
const duckDB = yield* DuckDB.Service.pipe(Effect.option) // optional, read-only client
const fs = yield* AppFileSystem.Service

return {
  parameters: Schema.Struct({ ... }),
  execute: (params) => Effect.gen(function* () {
    // 1. Write to DuckDB if available (via a dedicated write client, NOT DuckDB.Service)
    //    The write client needs to be obtained separately — see Writes section below.

    // 2. Always also write to JSONL (canonical persistence)
    yield* fs.ensureDir(path.dirname(jsonlPath))
    yield* fs.writeFileString(jsonlPath, JSON.stringify(record) + "\n", { flag: "a" })

    // 3. Structured output
    return { title: "...", metadata: { ... }, output: JSON.stringify(result, null, 2) }
  }).pipe(Effect.orDie),
}
```

